<?php require __DIR__.'/includes/bootstrap.php';$cart=cart_details();if(!$cart['items'])redirect('cart.php');$u=user();if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$name=trim($_POST['customer_name']??'');$email=trim($_POST['customer_email']??'');if($name===''||!filter_var($email,FILTER_VALIDATE_EMAIL)){flash('error','Enter your name and a valid email.');redirect('checkout.php');}try{db()->beginTransaction();$num='GNM-'.date('ymd').'-'.strtoupper(bin2hex(random_bytes(3)));$st=db()->prepare("INSERT INTO booth_orders(order_number,booth_id,customer_user_id,customer_name,customer_email,shipping_address1,shipping_address2,shipping_city,shipping_state,shipping_postal,shipping_country,customer_note,subtotal,total,order_status,payment_status,payment_provider) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,'pending','pending','demo')");$st->execute([$num,$cart['booth_id'],$u['id']??null,$name,$email,trim($_POST['address1']??''),trim($_POST['address2']??''),trim($_POST['city']??''),trim($_POST['state']??''),trim($_POST['postal']??''),trim($_POST['country']??'United States'),trim($_POST['note']??''),$cart['subtotal'],$cart['subtotal']]);$oid=(int)db()->lastInsertId();$item=db()->prepare('INSERT INTO booth_order_items(order_id,product_id,product_name,sku,unit_price,quantity,line_total) VALUES(?,?,?,?,?,?,?)');$dec=db()->prepare('UPDATE booth_products SET inventory_quantity=inventory_quantity-? WHERE id=? AND inventory_quantity IS NOT NULL AND inventory_quantity>=?');foreach($cart['items'] as $p){$item->execute([$oid,$p['id'],$p['name'],$p['sku'],$p['price'],$p['quantity'],$p['line_total']]);$dec->execute([$p['quantity'],$p['id'],$p['quantity']]);}db()->commit();unset($_SESSION['booth_cart']);redirect('order-confirmation.php?order='.urlencode($num));}catch(Throwable $e){if(db()->inTransaction())db()->rollBack();flash('error','Could not create the order: '.$e->getMessage());redirect('checkout.php');}}
app_header('Demo Checkout');?>
<section class="dashboard-hero"><p class="eyebrow">CHECKOUT</p><h1>Complete Your Demo Order</h1><div class="alert info"><strong>No payment will be processed.</strong> This checkout demonstrates the full customer and seller experience while payment integration remains disabled.</div></section><section class="checkout-layout"><form method="post" class="form-card form-grid"><?=csrf_field()?><label>Name<input name="customer_name" value="<?=e($u['display_name']??'')?>" required></label><label>Email<input type="email" name="customer_email" value="<?=e($u['email']??'')?>" required></label><label class="full">Address<input name="address1"></label><label class="full">Address line 2<input name="address2"></label><label>City<input name="city"></label><label>State / Region<input name="state"></label><label>Postal code<input name="postal"></label><label>Country<input name="country" value="United States"></label><label class="full">Note to seller<textarea name="note" rows="4"></textarea></label><div class="full"><button class="button primary large">Place Demo Order</button></div></form><aside class="app-card cart-summary"><h2>Summary</h2><?php foreach($cart['items'] as $p):?><p><span><?=e($p['name'])?> × <?=$p['quantity']?></span><strong>$<?=number_format((float)$p['line_total'],2)?></strong></p><?php endforeach?><hr><p><span>Total</span><strong>$<?=number_format((float)$cart['subtotal'],2)?></strong></p><p class="muted">Payment provider: Demo</p></aside></section><?php app_footer();